add := func(a int, b int) int {
    return a + b
}
square := func(x int) int {
    return x * x
}
apply := func(f func(int) int, x int) int {
    return f(x)
}
result := apply(square, 5)

counter := 0
var wg sync.WaitGroup
increment := func() {
    defer wg.Done()
    counter++
}

for i := 0; i < 10; i++ {
    wg.Add(1)
    go increment()
}
wg.Wait()

